// Exemple s'exécutant dans un environnement Node.js (syntaxe ESM)
import { writeFile, readFile } from 'fs/promises';

async function gererFichier() {
    const chemin = './notes.txt';
    try {
        // Écriture asynchrone non-bloquante
        await writeFile(chemin, 'Contenu textuel en JS', 'utf-8');

        // Lecture
        const contenu = await readFile(chemin, 'utf-8');
        console.log(contenu);
    } catch (err) {
        console.error("Erreur E/S :", err.message);
    }
}

gererFichier();
